209	
210	    if (aspectRatio != undefined) {
211	      warnings.push({
212	        type: 'unsupported',
213	        feature: 'aspectRatio',
214	        details:
215	          'This model does not support aspect ratio. Use `size` instead.',
216	      });
217	    }
218	
219	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
220	    const { value: response, responseHeaders } = await postJsonToApi({
221	      url: this.getUrl(this.modelId),
222	      headers: await resolve(
223	        combineHeaders(await resolve(this.config.headers), headers),
224	      ),
225	      body: args,
226	      failedResponseHandler: createJsonErrorResponseHandler({
227	        errorSchema: BedrockErrorSchema,
228	        errorToMessage: error => `${error.type}: ${error.message}`,
229	      }),
230	      successfulResponseHandler: createJsonResponseHandler(
231	        bedrockImageResponseSchema,
232	      ),
233	      abortSignal,
234	      fetch: this.config.fetch,
235	    });
