```

#### Pattern 3: Provider with Complex Task Types (Amazon Bedrock - `/packages/amazon-bedrock/src/bedrock-image-model.ts`)

Bedrock demonstrates multiple task types:

```typescript
export class BedrockImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly provider = 'amazon-bedrock';

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<...> {
    const warnings: Array<SharedV3Warning> = [];

    let args: Record<string, unknown>;

    if (files != null && files.length > 0) {
      const taskType =
        providerOptions?.bedrock?.taskType ??
        (hasMask ? 'INPAINTING' : 'IMAGE_VARIATION');

      switch (taskType) {
        case 'INPAINTING': { /* ... */ }
        case 'OUTPAINTING': { /* ... */ }
        case 'BACKGROUND_REMOVAL': { /* ... */ }
        case 'IMAGE_VARIATION': { /* ... */ }
      }
    } else {
      // TEXT_IMAGE mode
      args = { taskType: 'TEXT_IMAGE', ... };
    }

    return { images, warnings, response, ... };
  }
}
```

#### Pattern 4: OpenAI - Dual Mode (Edit vs Generate)

**File**: `/packages/openai/src/image/openai-image-model.ts`

OpenAI implementation demonstrates conditional behavior based on presence of `files`:

```typescript
export class OpenAIImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    return modelMaxImagesPerCall[this.modelId] ?? 1;
  }

  async doGenerate({
    prompt,
    files,
    mask,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<...> {
    const warnings: Array<SharedV3Warning> = [];

    // Image editing mode (when files are provided)
    if (files != null) {
      const { value: response, responseHeaders } = await postFormDataToApi({
        url: this.config.url({ path: '/images/edits', modelId: this.modelId }),
        formData: convertToFormData<OpenAIImageEditInput>({
          model: this.modelId,
          prompt,
          image: await Promise.all(
            files.map(file =>
              file.type === 'file'
                ? convertFileToBlob(file)
                : downloadBlob(file.url),
            ),
          ),
          mask: mask != null ? await fileToBlob(mask) : undefined,
          n,
          size,
          ...(providerOptions.openai ?? {}),
        }),
        // ...
      });

      return {
        images: response.data.map(item => item.b64_json),
        warnings,
        providerMetadata: {
          openai: {
            images: response.data.map((item, index) => ({
              ...(item.revised_prompt ? { revisedPrompt: item.revised_prompt } : {}),
              created: response.created ?? undefined,
              // ...
            })),
          },
        },
        response: { timestamp, modelId, headers: responseHeaders },
      };
    }

    // Image generation mode (standard)
    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({ path: '/images/generations', modelId: this.modelId }),
      body: {
        model: this.modelId,
        prompt,
        n,
        size,
        ...(providerOptions.openai ?? {}),
      },
      // ...
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: { timestamp, modelId, headers: responseHeaders },
      // ...
    };
  }
}
```

### Key Implementation Requirements

1. **Class must implement ImageModelV3 interface**
   - Readonly `specificationVersion = 'v3'`
   - Readonly `provider` (string)
   - Readonly `modelId` (passed via constructor)
   - `maxImagesPerCall` property (number, undefined, or function)
   - `doGenerate()` async method

2. **doGenerate() Must Return**
   - `images`: Array<string> (base64) or Array<Uint8Array> (binary)
   - `warnings`: SharedV3Warning[]
   - `response`: { timestamp, modelId, headers }
   - `providerMetadata`: Optional provider-specific metadata (keyed by provider name)
   - `usage`: Optional token counts

3. **Common Utilities Used**
   - `postJsonToApi()` / `postFormDataToApi()` for API calls
   - `combineHeaders()` for header management
   - `createJsonResponseHandler()` for response parsing
   - `parseProviderOptions()` for provider-specific options
   - `convertBase64ToUint8Array()` / `convertUint8ArrayToBase64()` for data conversion
   - `downloadBlob()` for URL-based images
   - `createJsonErrorResponseHandler()` for error handling

4. **Common Configuration Pattern**
   ```typescript
   interface ProviderImageModelConfig {
     provider: string;
     baseURL?: string;
     url?: (opts: { path: string; modelId: string }) => string;
     headers?: Resolvable<Record<string, string | undefined>>;
     fetch?: FetchFunction;
     _internal?: {
       currentDate?: () => Date;
     };
   }
   ```

5. **Provider Options Structure**
   - Keyed by provider name in `providerOptions`
   - Example: `providerOptions.openai`, `providerOptions.google`, `providerOptions.fal`
   - Parsed using provider-specific schemas (Zod)

This pattern ensures consistency across all image model providers while allowing flexibility for provider-specific capabilities and task types.

