import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { FetchFunction, InferSchema, Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';

// ---------------------------------------------------------------------------
// Internal config passed from the provider factory to each model instance
// ---------------------------------------------------------------------------

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  /** Default model-level settings (can be overridden per-call via providerOptions) */
  settings?: PixelArtImageSettings;
  _internal?: {
    currentDate?: () => Date;
  };
}

// ---------------------------------------------------------------------------
// Provider-options schema (Zod v4)
// Parsed from `providerOptions.pixelart` at call time.
// ---------------------------------------------------------------------------

export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * Output image size, e.g. `"512x512"`.
       * Overrides the standard `size` parameter and model-level default.
       */
      size: z.string().optional(),

      /**
       * Visual art style for the generated image.
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),

      /**
       * Pixel density (dots per unit).
       */
      pixelDensity: z.number().positive().optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

// ---------------------------------------------------------------------------
// Response / error schemas
// ---------------------------------------------------------------------------

const pixelArtResponseSchema = z.object({
  data: z.array(z.object({ b64_json: z.string() })),
  model: z.string().optional(),
});

const pixelArtErrorSchema = z.object({
  error: z
    .object({
      message: z.string().optional(),
      code: z.string().optional(),
    })
    .optional(),
  message: z.string().optional(),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: data =>
    data.error?.message ?? data.message ?? 'Unknown PixelArt error',
});

// ---------------------------------------------------------------------------
// Image model implementation
// ---------------------------------------------------------------------------

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  /**
   * Maximum number of images that can be requested in a single API call.
   */
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size: callSize,
      aspectRatio,
      seed,
      files,
      mask,
      providerOptions,
      headers: callHeaders,
      abortSignal,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    // ------------------------------------------------------------------
    // Warn about unsupported standard parameters
    // ------------------------------------------------------------------

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use the size setting instead.',
      });
    }

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'PixelArt does not support seed for reproducible generation.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details:
          'PixelArt does not support image-to-image generation. Input files are ignored.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt does not support inpainting. Mask is ignored.',
      });
    }

    // ------------------------------------------------------------------
    // Parse provider-specific options
    // ------------------------------------------------------------------

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    // Precedence: call-time providerOptions > call-time size param > model defaults
    const finalSize =
      pixelartOptions?.size ?? callSize ?? this.config.settings?.size;
    const finalStyle =
      pixelartOptions?.style ?? this.config.settings?.style;
    const finalPixelDensity =
      pixelartOptions?.pixelDensity ?? this.config.settings?.pixelDensity;

    // ------------------------------------------------------------------
    // Build request body
    // ------------------------------------------------------------------

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      ...(finalSize != null && { size: finalSize }),
      ...(finalStyle != null && { style: finalStyle }),
      ...(finalPixelDensity != null && { pixel_density: finalPixelDensity }),
    };

    // ------------------------------------------------------------------
    // Make API call
    // ------------------------------------------------------------------

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), callHeaders),
      body,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    // ------------------------------------------------------------------
    // Return result
    // ------------------------------------------------------------------

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        modelId: response.model ?? this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: response.data.map(() => ({
            ...(finalStyle != null && { style: finalStyle }),
            ...(finalPixelDensity != null && {
              pixelDensity: finalPixelDensity,
            }),
          })),
        },
      },
    };
  }
}

