import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import {
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import type {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';
import { VERSION } from './version';

// ---------------------------------------------------------------------------
// Public types
// ---------------------------------------------------------------------------

/**
 * Configuration options for the PixelArt provider factory.
 */
export interface PixelArtProviderSettings {
  /**
   * PixelArt API key.
   * Defaults to the `PIXELART_API_KEY` environment variable.
   */
  apiKey?: string;

  /**
   * Base URL for API calls.
   * Defaults to `https://api.pixelart.ai/v1`.
   */
  baseURL?: string;

  /**
   * Custom HTTP headers included in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation. Useful for middleware, interceptors, or
   * testing with a mock server.
   */
  fetch?: FetchFunction;
}

/**
 * PixelArt provider interface.
 *
 * Only image generation is supported. Calling `languageModel` or
 * `embeddingModel` throws `NoSuchModelError`.
 */
export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates an image generation model.
   *
   * @param modelId - The PixelArt model ID (e.g. `"pixelart-v1"`).
   * @param settings - Optional default settings applied to every generation call.
   */
  image(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;

  /**
   * Alias for `image()`.
   */
  imageModel(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;
}

// ---------------------------------------------------------------------------
// Factory
// ---------------------------------------------------------------------------

const defaultBaseURL = 'https://api.pixelart.ai/v1';

/**
 * Creates a PixelArt provider instance.
 *
 * @example
 * ```ts
 * import { createPixelArt } from '@ai-sdk/pixelart';
 *
 * const pixelart = createPixelArt({ apiKey: process.env.PIXELART_API_KEY });
 * const model = pixelart.image('pixelart-v1', { style: 'retro' });
 * ```
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(options.baseURL) ?? defaultBaseURL;

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
      settings,
    });

  return {
    specificationVersion: 'v3',
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
    },
  };
}

/**
 * Default PixelArt provider instance.
 *
 * Uses `PIXELART_API_KEY` from the environment and the default base URL.
 */
export const pixelart = createPixelArt();

